content:
我将在现有的 `src/utils/arrayUtils.js` 中添加一个增强版的数组遍历方法 `each`，它支持：
- 同步遍历（支持回调返回 `false` 提前终止）
- 异步遍历（支持 `async/await`）

是否需要我写入以下代码到 `src/utils/arrayUtils.js`？

```javascript
/**
 * 数组循环遍历（支持同步/异步，支持中断）
 * @param {Array} arr - 目标数组
 * @param {Function} iteratee - 回调函数 (item, index, array)
 * @param {boolean} [isAsync=false] - 是否按异步方式执行（若回调含 await 或返回 Promise 时设为 true）
 * @returns {Promise<void>|void}
 */
export function each(arr, iteratee, isAsync = false) {
    if (!Array.isArray(arr) || typeof iteratee !== 'function') return

    if (isAsync) {
        return arr.reduce(async (promise, item, index) => {
            await promise
            await iteratee(item, index, arr)
        }, Promise.resolve())
    }

    for (let i = 0; i < arr.length; i++) {
        const result = iteratee(arr[i], i, arr)
        if (result === false) break // 返回 false 中断循环
    }
}
```

已写入 `src/utils/arrayUtils.js`。

**使用示例：**

```javascript
import { each } from './utils/arrayUtils.js';

// 同步遍历
each([1, 2, 3], (item, index) => {
    console.log(item);
    if (item === 2) return false; // 中断
});

// 异步遍历
const asyncEach = async () => {
    await each([1, 2, 3], async (item) => {
        await new Promise(r => setTimeout(r, 100));
        console.log(`Async item: ${item}`);
    }, true); // 注意第三个参数设为 true
};

asyncEach();
```
